const Q_BIOLOGY_2005=[{"id": "objective>Biology>2005>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organelle common to both plant and animal cells is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">centriole </div>", "<div style=\"font-family:Cambria;font-size:17px;\">plasmalemma</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cell wall </div>", "<div style=\"font-family:Cambria;font-size:17px;\">chloroplast</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The organelle common to both plant and animal cells is the plasmalemma, also known as the cell membrane. The cell membrane (plasmalemma) is a biological membrane that separates the interior of all cells from the outside environment which protects the cell from its environment. The cell membrane consists of a lipid bilayer, including cholesterols that sit between phospholipids to maintain their fluidity at various temperatures. The membrane also contains membrane proteins, including integral proteins that go across the membrane and peripheral proteins that loosely attach to the outer (extracellular face) or inner (cytoplasmic face) surfaces of the membrane.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2005>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is likely to have a higher concentration of mitochondria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sperm cell </div>", "<div style=\"font-family:Cambria;font-size:17px;\">white blood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">egg cell </div>", "<div style=\"font-family:Cambria;font-size:17px;\">red blood cell</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mitochondria are the powerhouses of the cell, providing energy for cell functions. Sperm cells require a lot of energy to move towards the egg for fertilization, hence they have a higher concentration of mitochondria. White blood cells, egg cells, and red blood cells do not require as much energy as sperm cells.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2005>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The hyphal wall of fungi is rigid owing to the presence of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cell wall </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lignin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cellulose </div>", "<div style=\"font-family:Cambria;font-size:17px;\">chitin</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The hyphal wall of fungi is rigid due to the presence of chitin. Chitin is a long-chain polymer of a N-acetylglucosamine, a derivative of glucose, and is found in many places throughout the natural world. It is the main component in the cell walls of fungi, the exoskeletons of arthropods, such as crustaceans and insects, the radulae of mollusks, and the beaks and internal shells of cephalopods.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : FUNGI"}, {"id": "objective>Biology>2005>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Angiosperms and gymnosperms belong to the class</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">schizophyta </div>", "<div style=\"font-family:Cambria;font-size:17px;\">spermatophyte</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pteridophyta </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bryophyta</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Angiosperms and gymnosperms belong to the class Spermatophyta. Spermatophyta, also known as phanerogams, are seed-producing plants. They are distinguished from all other plants by having ovules (and therefore seeds) that are fully enclosed within carpels. The group includes the angiosperms (flowering plants), the gymnosperms (conifers, cycads, and ginkgos), and a few extinct groups.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : PLANTAE"}, {"id": "objective>Biology>2005>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a radially symmetrical organism is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">planaria </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydra </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tapeworm </div>", "<div style=\"font-family:Cambria;font-size:17px;\">roundworm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Radial symmetry is a type of symmetry where an organism can be divided into similar halves by more than two planes passing through the center. Hydra is an example of a radially symmetrical organism. It can be divided into similar halves in multiple ways.</div>", "topic": "LIVING ORGANISMS : CHARACTERISTICS"}, {"id": "objective>Biology>2005>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The leech and the earthworm belong to the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">molluscs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">crustaceans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">arachnids </div>", "<div style=\"font-family:Cambria;font-size:17px;\">annelids</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The leech and the earthworm belong to the Annelids. Annelids are a large phylum of segmented worms, with over 22,000 extant species including ragworms, earthworms, and leeches.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : ANIMALIA"}, {"id": "objective>Biology>2005>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. <span style=\"font-style:italic;\"> Ratttus rattus </span> <br/> II. <span style=\"font-style:italic;\"> Agama agama </span> <br/> III. <span style=\"font-style:italic;\"> Bufo regularis </span> <br/>  IV. <span style=\"font-style:italic;\"> Tilapia zilli </span> <br/> The order of evolutionary advancement of the above vertebrates is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II, III, IV </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, IV, III, II </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III, IV, I </div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV, III, II, I</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The order of evolutionary advancement of the vertebrates listed would be IV, III, II, I. This is because fish (<span style=\"font-style:italic;\"> Tilapia zilli </span>) evolved first, followed by amphibians (<span style=\"font-style:italic;\"> Bufo regularis </span>), then reptiles (Agama agama), and finally mammals (<span style=\"font-style:italic;\"> Rattus rattus </span>).</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : ANIMALIA"}, {"id": "objective>Biology>2005>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The angle between the parts labeled II and III is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bud </div>", "<div style=\"font-family:Cambria;font-size:17px;\">node </div>", "<div style=\"font-family:Cambria;font-size:17px;\">internode </div>", "<div style=\"font-family:Cambria;font-size:17px;\">axil</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An Axil is the angle between the stem and leaf bud. An axil is the angle between the upper side of a leaf or stem and the stem or branch from which it grows. This area is significant in botany because it's where buds often form, which can develop into new branches, leaves, or flowers.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : STEM"}, {"id": "objective>Biology>2005>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The part of the plant where photosynthesis is least likely to take place is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II </div>", "<div style=\"font-family:Cambria;font-size:17px;\">III </div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">IV is the root, Photosynthesis will least likely take place in the root because it is below the ground and sunlight doesn't ge there.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2005>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The stage in the life history of a moth responsible for the destruction of agricultural crops is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nymph </div>", "<div style=\"font-family:Cambria;font-size:17px;\">imago </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pupa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">caterpillar</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Caterpillars are the larval stage of moths and butterflies and are known for their voracious appetite. They feed on leaves and can cause significant damage to crops.</div>", "topic": "ADAPTATION FOR SURVIVAL : COMPETITION"}, {"id": "objective>Biology>2005>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The blackfly is a vector of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">malaria </div>", "<div style=\"font-family:Cambria;font-size:17px;\">trypanosomiasis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">onchocerciasis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">yellow fever</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Onchocerciasis, also known as river blindness, is a disease caused by the parasitic worm Onchocerca volvulus. It is transmitted to humans through the bite of a blackfly.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2005>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The transition from amphibians to mammals involves the limbs becoming arranged to support the weight more effectively requiring modifications in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">collar bones and coccyx</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pectoral and pelvic girdles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scapulae and clavicles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vertebrae and sternum</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pectoral and pelvic girdles are the parts of the skeleton that support the limbs. In the transition from amphibians to mammals, these parts of the skeleton had to be modified to support the weight of the body more effectively.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2005>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main function of the caudal fin in Tilapia is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">propel it forward in water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">steer it while changing direction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">balance it in water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enable it to float in water</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The caudal fin, also known as the tail fin, in fish like Tilapia is primarily used for propulsion. It helps the fish to move forward in water. The other fins are used for steering, balancing and braking.</div>", "topic": "STRUCTURAL/BEHAVIOURAL ADAPTATIONS OF VERTEBRATES : BONY FISH"}, {"id": "objective>Biology>2005>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the root vascular system, the stele is directly surrounded by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pericycle </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cortex</div>", "<div style=\"font-family:Cambria;font-size:17px;\">endodermis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">parenchyma</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the root vascular system of a plant, the stele, which is the central part of the root or stem containing the tissues derived from the procambium, is directly surrounded by the endodermis. The endodermis is a single layer of cells that border the stele and acts as a barrier between the stele and the cortex, controlling the flow of nutrients into the vascular system.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : ROOT"}, {"id": "objective>Biology>2005>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The part labeled IV represents the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">colon </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ileum </div>", "<div style=\"font-family:Cambria;font-size:17px;\">caecum </div>", "<div style=\"font-family:Cambria;font-size:17px;\">duodenum</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The duodenum precedes the jejunum and ileum and is the shortest part of the small intestine, where most chemical digestion takes place.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>2005>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The bile is stored in the part labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II </div>", "<div style=\"font-family:Cambria;font-size:17px;\">III </div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The bile is stored in the part labelled II.The part labelled II is known as the \"\"gall bladder</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>2005>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The only vein that carries pure oxygenated blood is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">renal vein </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pulmonary vein</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hepatic vein </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sciatic vein</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pulmonary vein is the only vein that carries pure oxygenated blood. It carries oxygenated blood from the lungs back to the left atrium of the heart. This is in contrast to other veins in the body, which carry deoxygenated blood.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2005>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The function of the fluid-filled pericardium is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reduce the friction caused by the pumping movements of the heart</div>", "<div style=\"font-family:Cambria;font-size:17px;\">supply the heart with oxygen and nutrients</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent disease organisms from attacking the heart</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce the intensity of the pumping action of the heart</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pericardium is a double-walled sac containing the heart and the roots of the great vessels. The function of the fluid-filled pericardium is to reduce the friction caused by the pumping movements of the heart. This fluid, known as pericardial fluid, acts as a lubricant to allow the heart to move and beat without causing damage or excessive friction.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2005>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mammalian lung is made airtight by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pleural cavity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mucous membrane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pleural membrane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diaphragm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mammalian lung is made airtight by the pleural membrane. The pleural membrane is a thin, moist, slippery layer of two membranes, one covering the lung (visceral pleura) and one covering the inner surface of the chest wall (parietal pleura). Between these two membranes is the pleural cavity which contains a small amount of lubricating pleural fluid. The two surfaces slide smoothly over each other as we breathe, and the airtight seal helps maintain pressure within the lungs.</div>", "topic": "RESPIRATION : RESPIRATORY ORGANS AND SURFACES"}, {"id": "objective>Biology>2005>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A test tube containing yeast in glucose solution was suspended in a covered conical flask containing alkaline pyrogallol. The bubbles of carbon (IV) oxide produced indicate that the yeast cells are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">respiring in the absence of oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liberating oxygen on their own</div>", "<div style=\"font-family:Cambria;font-size:17px;\">living and consuming oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">being killed by the alcohol produced</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If a test tube containing yeast in glucose solution was suspended in a covered conical flask containing alkaline pyrogallol and there is bubbling of Carbon(IV) Oxide that means that the yeast respire in the absence of oxygen.</div>", "topic": "RESPIRATION : AEROBIC RESPIRATION"}, {"id": "objective>Biology>2005>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The urinary tubules of the kidney function through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">osmosis and diffusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">active transport and osmosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ultrafiltration and selective reabsorption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">active transport and cytoplasmic streaming.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The urinary tubules of the kidney function through ultrafiltration and selective reabsorption. Ultrafiltration is the process where blood pressure forces small molecules such as water, glucose, amino acids, urea and salts across the walls of the glomerular capillaries and into the Bowman's capsule. Selective reabsorption is the process where useful substances needed by the body are reabsorbed back into the blood in the renal tubules of the nephron.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2005>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Excess water in plants is excreted as water vapour and droplets respectively through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">respiration and guttation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transpiration and guttation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">photosynthesis and guttation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">guttation and condensation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Excess water in plants is excreted as water vapour and droplets respectively through transpiration and guttation. Transpiration is the process where water is lost from the plant in the form of water vapour through the stomata. Guttation is the process where water droplets are excreted from the tips or edges of leaves of some plants.</div>", "topic": "EXCRETION : EXCRETORY PRODUCTS OF PLANTS"}, {"id": "objective>Biology>2005>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When bacteria swim from cold to warm regions, this is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">negative chemotaxis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">positive thermotaxis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">positive phototaxis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">negative phototaxis</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When bacteria swim from cold to warm regions, this is known as positive thermotaxis. Thermotaxis is the movement of an organism in response to temperature, and in this case, the bacteria are moving towards a warmer temperature, hence it is positive thermotaxis.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2005>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrostatic skeleton is the type of supporting system found in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mammals </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reptiles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oligochaetes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">arthropods</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrostatic skeleton is a type of supporting system found in organisms that do not have a hard exoskeleton or endoskeleton, such as soft-bodied invertebrates like earthworms (oligochaetes). It involves the use of fluid pressure for structural support. The fluid-filled compartments within the organism's body provide rigidity and resistance, allowing for movement and flexibility.</div>", "topic": "SUPPORT AND MOVEMENT : SUPPORTING TISSUES IN ANIMALS"}, {"id": "objective>Biology>2005>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows. <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The structure labeled I originates from the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">liver </div>", "<div style=\"font-family:Cambria;font-size:17px;\">kidney</div>", "<div style=\"font-family:Cambria;font-size:17px;\">small intestine </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stomach</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The structure is known as the ureter, it transport urine from the Kidney to the bladder.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>2005>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows. <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Birth control by vasectomy is achieved by severing the structure labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II </div>", "<div style=\"font-family:Cambria;font-size:17px;\">III </div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The structure Labelled (III) is known as the Vas deferens or sperm duct.it helps to conduct sperms rom the epididymis to seminal vesicle. Vasectomy is done by cutting this spermatic duct</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2005>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows. <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The main function of the structure labeled I is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">store food for the young plant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pull the young shoot above the ground</div>", "<div style=\"font-family:Cambria;font-size:17px;\">store water for the seedling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect the young plumule</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It store food for the young plant. The cotyledon contains starch and protein which nourish the embryo before it germinates and becomes a full-grown seedling.</div>", "topic": "GROWTH : GERMINATION OF SEEDS AND CONDITION NECESSARY FOR GERMINATION OF SEEDS"}, {"id": "objective>Biology>2005>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows. <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The type of germination illustrated is termed</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hypogeal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">epicotyl </div>", "<div style=\"font-family:Cambria;font-size:17px;\">epigeal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hypocotyls</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Epigeal germination is the type of germination in which the cotyledons are carried above the soil surface. It is associated majorly with dicotyledons .eg cowpea.</div>", "topic": "GROWTH : GERMINATION OF SEEDS AND CONDITION NECESSARY FOR GERMINATION OF SEEDS"}, {"id": "objective>Biology>2005>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The structure labeled I is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">incus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">malleus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hammer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stapes</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Stapes fits into the oval window which is an opening leading to the inner ear.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2005>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> A function of the part labeled II is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">equalize pressure on both sides of the tympanum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conduct sound waves to the brain </div>", "<div style=\"font-family:Cambria;font-size:17px;\">help the animal maintain balance or posture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transform sound waves into electric impulses</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equalize pressure on both sides of the tympanum. The part labeled II is the eustachian tube. <br/> The Eustachian tube in the ear functions to equalize air pressure between the middle ear and the atmosphere, facilitates drainage of mucus, allows ventilation for the middle ear, and protects against pathogens, thus maintaining ear health and function.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2005>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a homeostatic response in humans?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Withdrawing and hand from a hot object</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The mouth getting watery when food is sighted</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Yawning owing to tiredness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shivering in a cold environment</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Homeostasis is the ability of an organism to maintain a stable, constant internal environment, despite changes in external conditions. Shivering in a cold environment is a homeostatic response in humans. When the body temperature drops, the muscles involuntarily contract and relax rapidly (shiver) to generate heat and restore the body temperature to its normal range.</div>", "topic": "COORDINATION AND CONTROL : HOMEOSTASIS"}, {"id": "objective>Biology>2005>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The optimal temperature for breeding cockroaches is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15°C </div>", "<div style=\"font-family:Cambria;font-size:17px;\">19°C </div>", "<div style=\"font-family:Cambria;font-size:17px;\">24°C </div>", "<div style=\"font-family:Cambria;font-size:17px;\">33°C</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At 24°C, the quantity of cockroaches is maximal showing that the temperature is most suitable.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2005>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> At which temperature will cockroaches not survive after 10days?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15°C </div>", "<div style=\"font-family:Cambria;font-size:17px;\">19°C </div>", "<div style=\"font-family:Cambria;font-size:17px;\">24°C </div>", "<div style=\"font-family:Cambria;font-size:17px;\">33°C</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">15°C. Cockroaches, being ectothermic, thrive in warmer temperatures but struggle to survive prolonged exposure to temperatures around 15 degrees Celsius due to their cold sensitivity and reduced metabolic activity, which can lead to impaired functioning and potential death.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2005>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Evaporation and transpiration are respectively represented by the components labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III and IV </div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV and I</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Evaporation and transpiration are respectively represented by the components labelled I and II </div>", "topic": "ECOLOGY : ENERGY FLOW IN THE ECOSYSTEM"}, {"id": "objective>Biology>2005>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The main reservoir of water in the cycle is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cloud </div>", "<div style=\"font-family:Cambria;font-size:17px;\">groundwater </div>", "<div style=\"font-family:Cambria;font-size:17px;\">plant </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ocean</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ocean is the main reservoir of water in the water cycle.</div>", "topic": "ECOLOGY : ENERGY FLOW IN THE ECOSYSTEM"}, {"id": "objective>Biology>2005>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Mambilla plateau is a unique Nigerian biome located in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Plateau state </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Borno state</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Taraba state </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Benue state</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Mambilla Plateau is a unique Nigerian biome located in Taraba State. A biome is a large community of plants and animals that occupies a distinct region. The Mambilla Plateau, with its unique climate and vegetation, is one such distinct region in Nigeria.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : HIGHLANDS OF MONTANE FORESTS AND GRASSLANDS"}, {"id": "objective>Biology>2005>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, the Guinea savanna belt borders the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mangrove swamps and the Sahel savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rainforests and the sudan savanna </div>", "<div style=\"font-family:Cambria;font-size:17px;\">deserts and sudan savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rainforests and the desert</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, the Guinea savanna belt borders the rainforests and the Sudan savanna. The Guinea savanna is a type of grassland that is found between the rainforest and the Sudan savanna. It is characterized by tall grasses and scattered trees.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : GUINEA SAVANNA"}, {"id": "objective>Biology>2005>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The population density of Tridax in an abandoned square farmland of side 200m <br/> was found to be 5plants per m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>. The population size of the plant on the farm is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1000 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">40000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200000</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">L = 200m  <br/>  Population density = Population ÷ Area = 5 plants m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>  <br/>  A = L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 200<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 40,000  <br/>  Population = 5 × 40,000 = 200,000.</div>", "topic": "THE ECOLOGY OF POPULATIONS : POPULATION DENSITY AND OVERCROWDING"}, {"id": "objective>Biology>2005>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Secondary succession is much faster than primary succession because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pioneer colonizers are more in number</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soil is already present</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secondary series require less nutrients</div>", "<div style=\"font-family:Cambria;font-size:17px;\">species competition is increased</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Secondary succession is much faster than primary succession because soil is already present. Primary succession begins in lifeless areas where there is no soil. In contrast, secondary succession begins in areas where a community that previously existed has been removed; it is typified by smaller scale disturbances that do not eliminate all life and nutrients from the environment.</div>", "topic": "THE ECOLOGY OF POPULATIONS : ECOLOGICAL SUCCESSION"}, {"id": "objective>Biology>2005>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is used to test for the presence of lime in a soil sample?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lime in soil can be tested using Hydrochloric acid (HCl). When HCl is added to a soil sample containing lime, it reacts to produce carbon dioxide gas which can be observed as effervescence or bubbling. This is due to the reaction between the acid and the calcium carbonate (lime) in the soil.</div>", "topic": "SOIL : CHARACTERISTICS OF DIFFERENT TYPES OF SOIL"}, {"id": "objective>Biology>2005>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The importance of practicing crop rotation in agriculture is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maintain soil fertility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">improve the nutritional value of crops</div>", "<div style=\"font-family:Cambria;font-size:17px;\">control soil erosion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure the growth of crops</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Crop rotation is the practice of growing different types of crops in the same area in sequenced seasons. It is done so that the soil of farms is not used for only one set of nutrients. It helps in reducing soil erosion and increases soil fertility and crop yield. Growing the same crop in the same place for many years in a row gradually depletes the soil of certain nutrients and crop rotation is a way to help maintain soil fertility.</div>", "topic": "SOIL : SOIL FERTILITY"}, {"id": "objective>Biology>2005>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The recycling method of solid waste disposal is unsuitable for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">organic matter </div>", "<div style=\"font-family:Cambria;font-size:17px;\">glass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plastics </div>", "<div style=\"font-family:Cambria;font-size:17px;\">metal scraps</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The recycling method of solid waste disposal is unstable for organic matter. Recycling is unsuitable for organic matter because it decomposes, causing odors and attracting pests, and can contaminate recyclable materials. Organic waste is biodegradable and better suited for composting, which converts it into nutrient-rich compost. Recycling facilities are not equipped to handle organic matter, and improper disposal can increase methane emissions. Composting or anaerobic digestion are more appropriate and environmentally friendly methods for managing organic waste.</div>", "topic": "HUMANS AND ENVIRONMENT : POLLUTION AND ITS CONTROL"}, {"id": "objective>Biology>2005>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A non-renewable alternative source of energy is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wind generators </div>", "<div style=\"font-family:Cambria;font-size:17px;\">solar panels</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nuclear energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydroelectric power</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A non-renewable energy source is one that cannot be replenished in a short period of time. Nuclear energy is a non-renewable energy source because it is derived from uranium, a material that is not replenished in nature. Wind generators, solar panels, and hydroelectric power are all renewable energy sources because they are derived from natural resources that are constantly replenished.</div>", "topic": "HUMANS AND ENVIRONMENT : CONSERVATION OF NATURAL RESOURCES"}, {"id": "objective>Biology>2005>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the best explanation for a child who is phenotypically short and born of two tall parents?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the father possesses a gene for shortness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the mother possesses a gene for shortness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nature makes the child short</div>", "<div style=\"font-family:Cambria;font-size:17px;\">both parents possess genes for shortness</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In genetics, height is considered a polygenic trait, meaning it is controlled by more than one gene. If both parents are tall but carry a recessive gene for shortness, they can produce a short child. This is because the child could inherit the recessive gene from both parents, resulting in a short phenotype. Therefore, the best explanation for a child who is phenotypically short and born of two tall parents is that both parents possess genes for shortness.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2005>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A yellow maize is crossed with a white maize and the first filial generation produce yellow maize only. The white trait is said to exhibit</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dominance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">recessiveness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">codominance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">incomplete dominance</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In genetics, when a trait is not expressed in the presence of another trait, it is said to be recessive. In the given question, when a yellow maize is crossed with a white maize and the first filial generation produces yellow maize only, it means that the yellow trait is dominant and the white trait is recessive. Therefore, the white trait is said to exhibit recessiveness.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2005>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The association in which one member benefits and the other is relatively unaffected by the interaction is termed</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">symbiosis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">parasitism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commensalism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mutualism</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The association where one organism benefits and the other is neither harmed nor benefits is called commensalism. In this type of relationship, one organism benefits from the other without affecting it. This is different from symbiosis where both organisms benefit, parasitism where one organism benefits at the expense of the other, and mutualism where both organisms benefit but are dependent on each other.</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>2005>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a peacock displays its colourful feathers, it is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ready for a fight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protecting itself from predators</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protecting its mate from predators </div>", "<div style=\"font-family:Cambria;font-size:17px;\">courting a female</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a peacock displays its colourful feathers, it is courting a female. This is a type of behavior known as a courtship display, which is common in many species. The male peacock uses its colourful feathers to attract a mate. This is not a sign of readiness for a fight, nor is it a method of protecting itself or its mate from predators.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2005>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When an animal has a dark-coloured dorsal surface and a light-coloured ventral surface, this is an adaptation called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">concealment coloration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">countershading </div>", "<div style=\"font-family:Cambria;font-size:17px;\">colour blending</div>", "<div style=\"font-family:Cambria;font-size:17px;\">disruptive coloration</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When an animal has a dark coloured dorsal surface and a light coloured ventral surface, this is an adaptation called counter shading. </div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2005>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The only caste in the termite colony whose members can feed themselves are the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reproductives </div>", "<div style=\"font-family:Cambria;font-size:17px;\">workers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nymphs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">soldiers</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a termite colony, the workers are the ones responsible for gathering food and feeding the rest of the colony. The other castes, such as the reproductives (queen and king), soldiers, and nymphs, rely on the workers for nourishment. Therefore, the workers are the only caste that can feed themselves.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2005>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An evidence of a common ancestry for fishes, amphibians, reptiles, birds and <br/> mammals is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">possession of wings by birds and bats</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cold-bloodedness of fishes, amphibians and reptiles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">presence of gill clefts in vertebrate embryos</div>", "<div style=\"font-family:Cambria;font-size:17px;\">possession of scales by fishes and reptiles</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of gill clefts in vertebrate embryos is a common feature among fishes, amphibians, reptiles, birds, and mammals. This suggests a common ancestry among these groups. Gill clefts are part of the pharyngeal arches, which are a series of outgrowths in the neck region of vertebrate embryos. In fishes, these develop into gills, while in terrestrial vertebrates, they give rise to various structures in the head and neck. <br/> <img src=\"2005/AXHCB6.jpg\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}];
